"use client";

import React, { createContext, useContext, useState, useEffect } from 'react';

// Types
export type Member = {
    id: number;
    name: string;
    role: string;
    status: "Activo" | "Pendiente" | "Inactivo";
    email: string;
    phone: string;
    avatar: string;
    color: string;
    badge: string;
};

export type Transaction = {
    id: number;
    type: "income" | "expense";
    category: string;
    description: string;
    amount: number;
    date: string;
    status: "Pagado" | "Pendiente";
};

type AppContextType = {
    members: Member[];
    transactions: Transaction[];
    addMember: (member: Omit<Member, 'id'>) => void;
    addTransaction: (transaction: Omit<Transaction, 'id'>) => void;
    deleteTransaction: (id: number) => void;
    getFinancials: () => { income: number; expense: number; balance: number };
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export function AppProvider({ children }: { children: React.ReactNode }) {
    // Initial Mock Data (Hydrated state)
    const [members, setMembers] = useState<Member[]>([
        { id: 1, name: "Maria García", role: "Fallera Mayor", status: "Activo", email: "maria.garcia@gmail.com", phone: "600123456", avatar: "MG", color: "from-rose-500 to-rose-600", badge: "2024" },
        { id: 2, name: "Jose Martínez", role: "Presidente", status: "Activo", email: "presidencia@falla.com", phone: "600654321", avatar: "JM", color: "from-amber-500 to-amber-600", badge: "PRES" },
        { id: 3, name: "Lucía Sanchis", role: "Corte Honor", status: "Pendiente", email: "lucia.sanchis@hotmail.com", phone: "600987654", avatar: "LS", color: "from-purple-500 to-purple-600", badge: "CH" },
    ]);

    const [transactions, setTransactions] = useState<Transaction[]>([
        { id: 1, type: "income", category: "Cuota", description: "Cuota Trimestral - Juan Pérez", amount: 60.00, date: "2024-02-09", status: "Pagado" },
        { id: 2, type: "income", category: "Lotería", description: "Venta Papeletas Navidad", amount: 1200.00, date: "2024-02-08", status: "Pagado" },
        { id: 3, type: "expense", category: "Monumento", description: "Pago Artista Fallero - 20%", amount: 4500.00, date: "2024-02-01", status: "Pagado" },
        { id: 4, type: "expense", category: "Pirotecnia", description: "Mascletà 18 Marzo", amount: 2500.00, date: "2024-01-20", status: "Pagado" },
    ]);

    const addMember = (member: Omit<Member, 'id'>) => {
        const newId = Math.max(...members.map(m => m.id), 0) + 1;
        setMembers([...members, { ...member, id: newId }]);
    };

    const addTransaction = (transaction: Omit<Transaction, 'id'>) => {
        const newId = Math.max(...transactions.map(t => t.id), 0) + 1;
        setTransactions([{ ...transaction, id: newId }, ...transactions]);
    };

    const deleteTransaction = (id: number) => {
        setTransactions(transactions.filter(t => t.id !== id));
    };

    const getFinancials = () => {
        const income = transactions.filter(t => t.type === "income").reduce((acc, curr) => acc + curr.amount, 0);
        const expense = transactions.filter(t => t.type === "expense").reduce((acc, curr) => acc + curr.amount, 0);
        return { income, expense, balance: income - expense };
    };

    return (
        <AppContext.Provider value={{ members, transactions, addMember, addTransaction, deleteTransaction, getFinancials }}>
            {children}
        </AppContext.Provider>
    );
}

export function useApp() {
    const context = useContext(AppContext);
    if (context === undefined) {
        throw new Error('useApp must be used within an AppProvider');
    }
    return context;
}
